import{_ as a,j as n,o as s,v as i}from"./chunks/framework.gVsiwu-7.js";const e=JSON.parse('{"title":"Kafka Brokers là gì ?","description":"","frontmatter":{"footer":true,"title":"Kafka Brokers là gì ?","authors":["lethanh"],"date":"2024-06-10T00:00:00.000Z","outline":"deep","draft":true,"group":"2.1 Kafka"},"headers":[{"level":2,"title":"Kafka Brokers là gì ?","slug":"kafka-brokers-la-gi","link":"#kafka-brokers-la-gi","children":[]},{"level":2,"title":"Vai trò của Kafka Brokers với Produce khi Produce gửi record đến Brokers","slug":"vai-tro-cua-kafka-brokers-voi-produce-khi-produce-gui-record-đen-brokers","link":"#vai-tro-cua-kafka-brokers-voi-produce-khi-produce-gui-record-đen-brokers","children":[]},{"level":2,"title":"Vai trò của Kafka Brokers với Consumer khi Consumer nhận record từ Brokers","slug":"vai-tro-cua-kafka-brokers-voi-consumer-khi-consumer-nhan-record-tu-brokers","link":"#vai-tro-cua-kafka-brokers-voi-consumer-khi-consumer-nhan-record-tu-brokers","children":[]},{"level":2,"title":"Topics và partitions","slug":"topics-va-partitions","link":"#topics-va-partitions","children":[{"level":3,"title":"Topics","slug":"topics","link":"#topics","children":[]},{"level":3,"title":"partitions","slug":"partitions","link":"#partitions","children":[{"level":4,"title":"Cách Kafka Broker map record đến partition.","slug":"cach-kafka-broker-map-record-đen-partition","link":"#cach-kafka-broker-map-record-đen-partition","children":[{"level":5,"title":"Cách 1: Xác định partition tại thời điểm tạo object ProducerRecord","slug":"cach-1-xac-đinh-partition-tai-thoi-điem-tao-object-producerrecord","link":"#cach-1-xac-đinh-partition-tai-thoi-điem-tao-object-producerrecord","children":[]}]}]}]},{"level":2,"title":"Một số lưu ý về Kafka Brokers","slug":"mot-so-luu-y-ve-kafka-brokers","link":"#mot-so-luu-y-ve-kafka-brokers","children":[]}],"relativePath":"study/thanhlv-study-2024/2024-06-10-kafka-brokers.md","filePath":"study/thanhlv-study-2024/2024-06-10-kafka-brokers.md","lastUpdated":1720670726000}'),t={name:"study/thanhlv-study-2024/2024-06-10-kafka-brokers.md"},r=[i('<nav class="table-of-contents"><ul><li><a href="#kafka-brokers-la-gi">Kafka Brokers là gì ?</a></li><li><a href="#vai-tro-cua-kafka-brokers-voi-produce-khi-produce-gui-record-đen-brokers">Vai trò của Kafka Brokers với Produce khi Produce gửi record đến Brokers</a></li><li><a href="#vai-tro-cua-kafka-brokers-voi-consumer-khi-consumer-nhan-record-tu-brokers">Vai trò của Kafka Brokers với Consumer khi Consumer nhận record từ Brokers</a></li><li><a href="#topics-va-partitions">Topics và partitions</a><ul><li><a href="#topics">Topics</a></li><li><a href="#partitions">partitions</a><ul><li><a href="#cach-kafka-broker-map-record-đen-partition">Cách Kafka Broker map record đến partition.</a><ul><li><a href="#cach-1-xac-đinh-partition-tai-thoi-điem-tao-object-producerrecord">Cách 1: Xác định partition tại thời điểm tạo object ProducerRecord</a></li></ul></li></ul></li></ul></li><li><a href="#mot-so-luu-y-ve-kafka-brokers">Một số lưu ý về Kafka Brokers</a></li></ul></nav><h1 id="overview-bai-viet-ve-kafka-brokers-la-gi" tabindex="-1">Overview bài viết về Kafka Brokers là gì ? <a class="header-anchor" href="#overview-bai-viet-ve-kafka-brokers-la-gi" aria-label="Permalink to &quot;Overview bài viết về Kafka Brokers là gì ?&quot;">​</a></h1><ul><li>Bài này sẽ giải thích cách kafka Broker hoạt động và lưu trữ trong Kafka event streaming platform</li><li>Mô tả cách Kafka Brokers xử lý các yêu cầu từ client cho việc ghi và đọc records.</li><li>Hiểu về Topic và Partitions</li><li>Sử dụng JMX metrics để kiểm tra Brokers</li></ul><h2 id="kafka-brokers-la-gi" tabindex="-1">Kafka Brokers là gì ? <a class="header-anchor" href="#kafka-brokers-la-gi" aria-label="Permalink to &quot;Kafka Brokers là gì ?&quot;">​</a></h2><ul><li>Kafka Brokers hay có thể gọi là Kafka server trong Kafka architecture và nó sẽ đóng vai trò lưu trữ dữ liệu(Storage layer) và nó có thể chạy thành một cluster và nó có thể mở rộng ra nhiều data centers. <img src="/assets/kafka-architecture-view.B_rra7lS.png" alt="kafka-architecture-view.png"></li><li>Kafka Brokers chịu trách nghiệm quản lý dữ liệu( Bao gồm lưu trữ, đọc và replication(Tạo bản sao để sao lưu) ), quản lý topic và partition và quản lý offset.</li><li>Tất nhiên, Kafka Brokers cũng nhận và xử lý trực tiếp các request từ client. <img src="/assets/kafka-handler-request.tA_aT67K.jpg" alt="kafka-handler-request.jpg"></li></ul><h2 id="vai-tro-cua-kafka-brokers-voi-produce-khi-produce-gui-record-đen-brokers" tabindex="-1">Vai trò của Kafka Brokers với Produce khi Produce gửi record đến Brokers <a class="header-anchor" href="#vai-tro-cua-kafka-brokers-voi-produce-khi-produce-gui-record-đen-brokers" aria-label="Permalink to &quot;Vai trò của Kafka Brokers với Produce khi Produce gửi record đến Brokers&quot;">​</a></h2><ul><li>Khi Produce muốn gửi Record đến Broker, Client Produce gửi records đến Broker đeer lưu trữ và consumer client có thể đọc các record đó sau. <img src="/assets/kafka-produce.MttxNzo5.jpg" alt="kafka-produce.jpg"> Hình ảnh phía trên mô tả Produce gửi record đến Brokers, trong thực tế, nhiều Client Produce sẽ giao tiếp với 1 số các Brokers trong cụm.</li></ul><h2 id="vai-tro-cua-kafka-brokers-voi-consumer-khi-consumer-nhan-record-tu-brokers" tabindex="-1">Vai trò của Kafka Brokers với Consumer khi Consumer nhận record từ Brokers <a class="header-anchor" href="#vai-tro-cua-kafka-brokers-voi-consumer-khi-consumer-nhan-record-tu-brokers" aria-label="Permalink to &quot;Vai trò của Kafka Brokers với Consumer khi Consumer nhận record từ Brokers&quot;">​</a></h2><p>Sau khi nói về yêu cầu của Produce chúng ta sẽ nói đến Consumer.</p><ul><li>Consumer client đưa ra yêu cầu đến Broker để đọc(Sử dụng) các Record từ một topic được các Produce gửi trước đó đên Broker. <img src="/assets/kafka-Consumer.PLcOqiQl.jpg" alt="kafka-Consumer.jpg"></li><li>Một điều quan trọng là sử dụng Record sẽ không làm ảnh hưởng đến việc lưu dữ liệu(Không bị mất sau khi đọc) hoặc việc sử dụng Record bởi các Consumer khác(Các consumer khác vẫn có thể đọc)</li></ul><h2 id="topics-va-partitions" tabindex="-1">Topics và partitions <a class="header-anchor" href="#topics-va-partitions" aria-label="Permalink to &quot;Topics và partitions&quot;">​</a></h2><h3 id="topics" tabindex="-1">Topics <a class="header-anchor" href="#topics" aria-label="Permalink to &quot;Topics&quot;">​</a></h3><ul><li>Kafka brokers sử dụng File system để lưu trữ bằng cách nối thêm các Record đến cuối cùng file trong một topic.</li><li>Một topic đại diện cho tên của Folder chưa tệp Kafka nối thêm các Record <img src="/assets/kafka-topic-1.AVPSldcv.jpg" alt="kafka-topic-1.jpg"></li><li>Kafka Brokers sẽ nhận key-value message dưới dạng raw byte, lưu trữ và phục vụ các yêu cầu đọc với cùng định dạng(Raw data). <ul><li>Kafka Brokers không biết về data type của Record(Chỉ nhận được các byte), bằng cách làm việc với raw byte, Brokers không mất thời gian deserializing hoặc serializing dữ liệu nên mạng lại hiệu suất cao hơn.</li></ul></li></ul><h3 id="partitions" tabindex="-1">partitions <a class="header-anchor" href="#partitions" aria-label="Permalink to &quot;partitions&quot;">​</a></h3><ul><li>Các topic sẽ đươc partition, một Partition là một số nguyên(number) bắt đầu từ 0. Vì vậy nếu một topic có 3 partition thì sẽ có số partition là 0, 1, 2.</li><li>Kafka brokers gắn số partition và đuôi của folder topic với format <code>{Topic name}-{partition number}</code>. <ul><li>Ví dụ một Topic tên <code>my-topic-2</code> có <code>5</code> partition thì tên sẽ như sau : <code>my-topic-2-0</code>, <code>my-topic-2-1</code>, <code>my-topic-2-2</code>, <code>my-topic-2-3</code>, , <code>my-topic-2-4</code>, <img src="/assets/kafka-partition-number.H1MC9uuH.jpg" alt="kafka-partition-number.jpg"></li></ul></li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>│   ....</span></span>\n<span class="line"><span>│   recovery-point-offset-checkpoint</span></span>\n<span class="line"><span>│   replication-offset-checkpoint</span></span>\n<span class="line"><span>│</span></span>\n<span class="line"><span>├───my-topic-2-0</span></span>\n<span class="line"><span>│       00000000000000000000.index</span></span>\n<span class="line"><span>│       00000000000000000000.log</span></span>\n<span class="line"><span>│       00000000000000000000.timeindex</span></span>\n<span class="line"><span>│       leader-epoch-checkpoint</span></span>\n<span class="line"><span>│       partition.metadata</span></span>\n<span class="line"><span>│</span></span>\n<span class="line"><span>├───my-topic-2-1</span></span>\n<span class="line"><span>│       00000000000000000000.index</span></span>\n<span class="line"><span>│       00000000000000000000.log</span></span>\n<span class="line"><span>│       00000000000000000000.timeindex</span></span>\n<span class="line"><span>│       leader-epoch-checkpoint</span></span>\n<span class="line"><span>│       partition.metadata</span></span>\n<span class="line"><span>│</span></span>\n<span class="line"><span>├───my-topic-2-2</span></span>\n<span class="line"><span>│       00000000000000000000.index</span></span>\n<span class="line"><span>│       00000000000000000000.log</span></span>\n<span class="line"><span>│       00000000000000000000.timeindex</span></span>\n<span class="line"><span>│       leader-epoch-checkpoint</span></span>\n<span class="line"><span>│       partition.metadata</span></span>\n<span class="line"><span>│</span></span>\n<span class="line"><span>├───my-topic-2-3</span></span>\n<span class="line"><span>│       00000000000000000000.index</span></span>\n<span class="line"><span>│       00000000000000000000.log</span></span>\n<span class="line"><span>│       00000000000000000000.timeindex</span></span>\n<span class="line"><span>│       leader-epoch-checkpoint</span></span>\n<span class="line"><span>│       partition.metadata</span></span>\n<span class="line"><span>│</span></span>\n<span class="line"><span>├───my-topic-2-4</span></span>\n<span class="line"><span>│      00000000000000000000.index</span></span>\n<span class="line"><span>│      00000000000000000000.log</span></span>\n<span class="line"><span>│      00000000000000000000.timeindex</span></span>\n<span class="line"><span>│      leader-epoch-checkpoint</span></span>\n<span class="line"><span>│      partition.metadata</span></span></code></pre></div><ul><li>Nhìn vào folder chúng ta có thể dễ hiểu được với tên topic là một nhóm dữ liệu và partititon là các đơn vị lưu trữ.</li><li>Trong hầu hết các case, số lượng của Partition càng cao thì throughput(Thông lượng) sẽ càng cao.</li></ul><h4 id="cach-kafka-broker-map-record-đen-partition" tabindex="-1">Cách Kafka Broker map record đến partition. <a class="header-anchor" href="#cach-kafka-broker-map-record-đen-partition" aria-label="Permalink to &quot;Cách Kafka Broker map record đến partition.&quot;">​</a></h4><ul><li>Producer client sẽ xác định Topic và partition cho record trước khi gửi nó đến Broker. <img src="/assets/kafka_broker-map-record-to-partition.QBNlkRTb.png" alt="kafka_broker-map-record-to-partition.png"></li><li>Thực tế xác định partition chúng ta có thể chia ra làm 2 cách như sau:</li></ul><h5 id="cach-1-xac-đinh-partition-tai-thoi-điem-tao-object-producerrecord" tabindex="-1">Cách 1: Xác định partition tại thời điểm tạo object ProducerRecord <a class="header-anchor" href="#cach-1-xac-đinh-partition-tai-thoi-điem-tao-object-producerrecord" aria-label="Permalink to &quot;Cách 1: Xác định partition tại thời điểm tạo object ProducerRecord&quot;">​</a></h5><p>Khi xây dựng ProducerRecord object, bạn set partition cho ProducerRecord thì producer sẽ sử dụng partition đó và gửi lên Broker.</p><details class="details custom-block"><summary>Xác định partition tại thời điểm tạo object ProducerRecord</summary><p><img src="/assets/map-partition-at-create-obj-ProducerRecord.by3wtdu7.png" alt="map-partition-at-create-obj-ProducerRecord.png"><img src="/assets/map-partition-at-create-obj-ProducerRecord-1.-mc7TllN.png" alt="map-partition-at-create-obj-ProducerRecord-1.png"></p></details><ul><li>Đối với java, thư viện sẽ sử dụng class <code>org.apache.kafka.clients.producer.internals.DefaultPartitioner</code> để xác định partition trước khi gửi đến.</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>public class DefaultPartitioner implements Partitioner {</span></span>\n<span class="line"><span>    private final StickyPartitionCache stickyPartitionCache = new StickyPartitionCache();</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    public DefaultPartitioner() {</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    public void configure(Map&lt;String, ?&gt; configs) {</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    public int partition(String topic, Object key, byte[] keyBytes, Object value, byte[] valueBytes, Cluster cluster) {</span></span>\n<span class="line"><span>        return this.partition(topic, key, keyBytes, value, valueBytes, cluster, cluster.partitionsForTopic(topic).size());</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    public int partition(String topic, Object key, byte[] keyBytes, Object value, byte[] valueBytes, Cluster cluster, int numPartitions) {</span></span>\n<span class="line"><span>        return keyBytes == null ? this.stickyPartitionCache.partition(topic, cluster) : Utils.toPositive(Utils.murmur2(keyBytes)) % numPartitions;</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    public void close() {</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    public void onNewBatch(String topic, Cluster cluster, int prevPartition) {</span></span>\n<span class="line"><span>        this.stickyPartitionCache.nextPartition(topic, cluster, prevPartition);</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>}</span></span></code></pre></div><p>Trong đoạn mã trên:</p><ol><li>partition Method: <ul><li>Method <code>partition</code> là nơi logic xác định <code>partition</code> được thực hiện.</li><li><code>Cluster</code> chứa thông tin về <code>cluster</code> cũng như các thông tin về <code>partition</code> của <code>topic</code>.</li><li><code>keyBytes</code> là mảng byte của khóa (nếu có).</li><li><code>valueBytes</code> là mảng byte của giá trị(data).</li></ul></li><li>Key-based Partitioning <ul><li>Nếu <code>keyBytes !== null</code> thì key-bash partition sẽ được thực hiện.</li><li>method <code>partition</code> sẽ sử dụng hàm băm <code>murmur2</code> để tính toán giá trị băm của key. <ul><li>Method <code>toPositive</code> sẽ giúp dữ liệu trả về luôn là số dương</li></ul></li><li>Giá trị hash sẽ được chia cho số lượng <code>partition(numPartitions)</code> để xác định <code>partition</code> sẽ được lưu trữ.<details class="details custom-block"><summary>Cùng 1 key sẽ được lưu vào cùng một partition</summary><p>Vì sử dụng key tính ra mã băm sau đó chia cho số lượng partition, vì vậy các <code>record</code> có cùng 1 key sẽ được lưu trên cùng một partition.</p><p>Điều này đảm bảo rằng các bản ghi có cũng key sẽ được lưu trữ trong cùng một partition, giúp duy trì order của các Record có cùng key.</p></details></li></ul></li><li>sticky Partition Cache</li></ol><ul><li>Thực tế, với kafka phiên bản trước <code>2.4</code> thì với trường hợp <code>key == null</code> thì partition sẽ sử dụng <code>Round-robin</code> bằng cách có 1 biến <code>count</code> theo <code>topic</code> và chia cho số lượng partition để được <code>Round-robin</code></li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>package org.apache.kafka.clients.producer.internals;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>import ...</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>public class StickyPartitionCache {</span></span>\n<span class="line"><span>    private final ConcurrentMap&lt;String, Integer&gt; indexCache = new ConcurrentHashMap();</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    public StickyPartitionCache() {</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    public int partition(String topic, Cluster cluster) {</span></span>\n<span class="line"><span>        Integer part = (Integer)this.indexCache.get(topic);</span></span>\n<span class="line"><span>        return part == null ? this.nextPartition(topic, cluster, -1) : part;</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    public int nextPartition(String topic, Cluster cluster, int prevPartition) {</span></span>\n<span class="line"><span>        List&lt;PartitionInfo&gt; partitions = cluster.partitionsForTopic(topic);</span></span>\n<span class="line"><span>        Integer oldPart = (Integer)this.indexCache.get(topic);</span></span>\n<span class="line"><span>        Integer newPart = oldPart;</span></span>\n<span class="line"><span>        if (oldPart != null &amp;&amp; oldPart != prevPartition) {</span></span>\n<span class="line"><span>            return (Integer)this.indexCache.get(topic);</span></span>\n<span class="line"><span>        } else {</span></span>\n<span class="line"><span>            List&lt;PartitionInfo&gt; availablePartitions = cluster.availablePartitionsForTopic(topic);</span></span>\n<span class="line"><span>            if (availablePartitions.size() &lt; 1) {</span></span>\n<span class="line"><span>                Integer random = Utils.toPositive(ThreadLocalRandom.current().nextInt());</span></span>\n<span class="line"><span>                newPart = random % partitions.size();</span></span>\n<span class="line"><span>            } else if (availablePartitions.size() == 1) {</span></span>\n<span class="line"><span>                newPart = ((PartitionInfo)availablePartitions.get(0)).partition();</span></span>\n<span class="line"><span>            } else {</span></span>\n<span class="line"><span>                while(newPart == null || newPart.equals(oldPart)) {</span></span>\n<span class="line"><span>                    int random = Utils.toPositive(ThreadLocalRandom.current().nextInt());</span></span>\n<span class="line"><span>                    newPart = ((PartitionInfo)availablePartitions.get(random % availablePartitions.size())).partition();</span></span>\n<span class="line"><span>                }</span></span>\n<span class="line"><span>            }</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            if (oldPart == null) {</span></span>\n<span class="line"><span>                this.indexCache.putIfAbsent(topic, newPart);</span></span>\n<span class="line"><span>            } else {</span></span>\n<span class="line"><span>                this.indexCache.replace(topic, prevPartition, newPart);</span></span>\n<span class="line"><span>            }</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            return (Integer)this.indexCache.get(topic);</span></span>\n<span class="line"><span>        }</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>}</span></span></code></pre></div><ul><li>Nếu <code>keyBytes == null</code> thì sticky Partition Cache sẽ được thực hiện.</li><li><code>sticky Partition Cache</code> đơn giản như sau, Nếu có <code>oldPart</code> hiện trả về <code>oldPart</code> ====&gt; <code>return part == null ? this.nextPartition(topic, cluster, -1) : part;</code></li><li>Sẽ có 2 trường hợp để lấy về partition mới(Gọi method <code>nextPartition</code>) <ul><li><ol><li>Nếu <code>oldPart == null</code> tức chưa xác định partition thì sẽ lấy và partition mới ==&gt; trong method <code>partition</code> ở StickyPartitionCache</li></ol></li><li><ol start="2"><li>Khi đã đến ngưỡng của <code>BATCH_SIZE_CONFIG</code> trong flow thực hiện tạo lại batch thì sẽ xác định lại partition ==&gt; trong method <code>onNewBatch</code> ở <code>DefaultPartitioner</code></li></ol></li></ul></li><li>Chốt lại đơn giản là partition sẽ được tính theo <code>BATCH</code>, tất cả các <code>Record</code> có <code>key == null</code> thì tất cả các Record trong cùng <code>BATCH của cùng 1 topic</code> đó sẽ trên cùng một <code>partition</code></li></ul><h2 id="mot-so-luu-y-ve-kafka-brokers" tabindex="-1">Một số lưu ý về Kafka Brokers <a class="header-anchor" href="#mot-so-luu-y-ve-kafka-brokers" aria-label="Permalink to &quot;Một số lưu ý về Kafka Brokers&quot;">​</a></h2><ul><li>Nếu tạo một Cluster kafka thì độ trễ của network nên ở mức dưới 15ms, vì việc liên lạc giữa các Kafka brokers là rất nhiều (Cả zookeeper nếu sử dụng zookeeper )</li></ul><h1 id="ref" tabindex="-1">REF: <a class="header-anchor" href="#ref" aria-label="Permalink to &quot;REF:&quot;">​</a></h1><ul><li><a href="https://ibm-cloud-architecture.github.io/refarch-eda/technology/kafka-overview/" target="_blank" rel="noreferrer">https://ibm-cloud-architecture.github.io/refarch-eda/technology/kafka-overview/</a></li><li><strong>Kafka book</strong>: <a href="/study/thanhlv-study-2024/static/Kafka%20Event%20Streaming%20Platform%20In%20Action.pdf">Kafka Event Streaming Platform In Action.pdf</a></li></ul>',33)];const c=a(t,[["render",function(a,i,e,t,c,o){return s(),n("div",null,r)}]]);export{e as __pageData,c as default};
